#include <iostream>
#include <string>
#include <algorithm>

int main() {
    std::string line1, line2, line3;
    std::getline(std::cin, line1);
    std::getline(std::cin, line2);
    std::getline(std::cin, line3);

    int cnt1[26] = {0}, cnt3[26] = {0};

    for (char c : line1) cnt1[c - 'A']++;
    for (char c : line2) cnt1[c - 'A']++;
    for (char c : line3) cnt3[c - 'A']++;

    bool ok = true;
    for (int i = 0; i < 26; i++) {
        if (cnt1[i] != cnt3[i]) {
            ok = false;
            break;
        }
    }

    std::cout << (ok ? "YES" : "NO") << std::endl;
    return 0;
}
